// // This module compares two 2-bit numbers and outputs whether the first number is less than or equal to the second number.
module magnitude_comparator (
    input [1:0] A,
    input [1:0] B,
    output A_gt_B,
    output A_eq_B,
    output A_lt_B
);
    assign A_gt_B = (A > B);
    assign A_eq_B = (A == B);
    assign A_lt_B = (A < B);
endmodule
